from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["first-pc-runtime-verification-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>First PC Runtime Verification</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#123256,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:8px}button{font:inherit;border-radius:16px;border:0;background:linear-gradient(135deg,#0284c7,#38bdf8);color:#02101b;font-weight:1000;padding:12px}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}.ok{color:#86efac;font-weight:900}.step{border-left:3px solid var(--ok);padding:8px 10px;background:#081226;border-radius:14px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>First PC Runtime Verification</h1><p class="muted">Primeiro teste real no PC: rotas essenciais, guia curto e fluxo recomendado.</p><div class="buttons"><button onclick="location.href='/app/home'" class="dark">Home</button><button onclick="checks()">Verificar Runtime</button><button onclick="guide()">Guia</button><button onclick="pkg()">Pacote completo</button></div></section><section class="panel"><h2>Fluxo real rápido</h2><div id="steps" class="grid"></div></section><section class="panel"><h2>Rotas essenciais</h2><div class="grid"><button onclick="location.href='/app/home'">Home</button><button onclick="location.href='/app/github-repo-inventory-feed'">Repo Inventory</button><button onclick="location.href='/app/repo-scanner-real-work-map'">Repo Scanner</button><button onclick="location.href='/app/real-work-fast-path'">Trabalho Real</button><button onclick="location.href='/app/conversation-source-import-feed'">Importar Conversa</button><button onclick="location.href='/app/provider-browser-local-launcher'">Provider Launcher</button><button onclick="location.href='/app/provider-broadcast-cockpit'">Broadcast IA</button><button onclick="location.href='/app/mobile-approval-cockpit-v2'">Aprovações</button></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);renderSteps(x?.guide||x)}function renderSteps(g){const arr=g?.first_real_flow||g?.pc_steps||[];qs('#steps').innerHTML=arr.map((s,i)=>`<div class="step"><b>${i+1}</b> ${String(s).replaceAll('<','&lt;')}</div>`).join('')}async function checks(){show(await api('/api/first-pc-runtime-verification/checks'))}async function guide(){show(await api('/api/first-pc-runtime-verification/guide'))}async function pkg(){show(await api('/api/first-pc-runtime-verification/package'))}pkg()</script></body></html>
"""


@router.get('/app/first-pc-runtime-verification', response_class=HTMLResponse)
async def first_pc_runtime_verification_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/pc-runtime-check', response_class=HTMLResponse)
async def pc_runtime_check_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
